import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { apiCall } from '../utils/api';

const AdminProducts = () => {
  const { user, token } = useAuth();
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [form, setForm] = useState({
    name: '',
    description: '',
    price: '',
    category: '',
    brand: '',
    image: '', // url string
    stock: ''
  });
  const [imageFile, setImageFile] = useState(null);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [error, setError] = useState('');

  useEffect(() => {
    if (user?.role === 'admin') {
      fetchProducts();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const fetchProducts = async () => {
    setLoading(true);
    try {
      const res = await apiCall.get('/products', {
        headers: { Authorization: `Bearer ${token}` },
        params: { admin: true }
      });
      const raw = res.data.products || [];
      // dedupe in case server returns duplicates
      const unique = Array.from(new Map(raw.map(p => [p._id, p])).values());
      setProducts(unique);
    } catch (err) {
      console.error('Error fetching products', err);
    } finally {
      setLoading(false);
    }
  };    


  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    setImageFile(file);
  };

  const handleAdd = async (e) => {
    e.preventDefault();
    setError('');
    try {
      let config = { headers: { Authorization: `Bearer ${token}` } };
      let data;

      if (imageFile) {
        data = new FormData();
        data.append('name', form.name);
        data.append('description', form.description);
        data.append('price', parseFloat(form.price));
        data.append('category', form.category);
        data.append('brand', form.brand);
        data.append('stock', parseInt(form.stock, 10));
        data.append('image', imageFile);
        if (editingId && form.visible !== undefined) {
          data.append('visible', form.visible);
        }
        config.headers['Content-Type'] = 'multipart/form-data';
      } else {
        data = {
          name: form.name,
          description: form.description,
          price: parseFloat(form.price),
          category: form.category,
          brand: form.brand,
          image: form.image,
          stock: parseInt(form.stock, 10)
        };
        if (editingId && form.visible !== undefined) {
          data.visible = form.visible;
        }
      }

      if (editingId) {
        await apiCall.put(`/products/${editingId}`, data, config);
        alert('✅ Product updated successfully!');
        setEditingId(null);
        setShowForm(false);
      } else {
        await apiCall.post('/products', data, config);
        alert('✅ Product added successfully!');
        setShowForm(false);
      }

      setForm({ name: '', description: '', price: '', category: '', brand: '', image: '', stock: '', visible: true });
      setImageFile(null);
      fetchProducts();
    } catch (err) {
      console.error(editingId ? 'Failed to update product' : 'Failed to add product', err);
      setError(
        err.response?.data?.error ||
        err.response?.data?.message ||
        (editingId ? 'Failed to update product' : 'Failed to add product')
      );
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this product?')) return;
    try {
      await apiCall.delete(`/products/${id}`, { headers: { Authorization: `Bearer ${token}` } });
      if (editingId === id) setEditingId(null);
      fetchProducts();
    } catch (err) {
      console.error('Failed to delete', err);
    }
  };

  const handleEdit = (product) => {
    console.log('handleEdit called for product:', product._id, product.name);
    setEditingId(product._id);
    setShowForm(true);
    setImageFile(null);
    setError('');
    setForm({
      name: product.name || '',
      description: product.description || '',
      price: product.price || '',
      category: product.category || '',
      brand: product.brand || '',
      image: product.image || '',
      stock: product.stock != null ? product.stock.toString() : '',
      visible: product.visible !== false
    });
    console.log('handleEdit completed - form should now display');
  };

  const [toggleLoading, setToggleLoading] = useState(null);

  const handleToggle = async (product) => {
    const newVisible = !product.visible;
    setToggleLoading(product._id);
    console.log('Making product visible:', product._id, product.name);
    try {
      const resp = await apiCall.put(
        `/products/${product._id}`,
        { visible: newVisible },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      
      const updatedProduct = resp.data.product;
      
      if (!updatedProduct) {
        alert('❌ Error: Could not update product');
        return;
      }
      
      // Update local state
      setProducts(prev => prev.map(p => p._id === product._id ? updatedProduct : p));
      
      // Show success
      if (newVisible) {
        alert('✅ Product is now VISIBLE to customers!');
      } else {
        alert('⚠️ Product is now HIDDEN from customers');
      }
      
      // Refresh to sync
      await fetchProducts();
    } catch (err) {
      console.error('Failed:', err);
      alert('❌ Failed: ' + (err.response?.data?.message || err.message));
    } finally {
      setToggleLoading(null);
    }
  };


  if (user?.role !== 'admin') {
    return <div>Access denied.</div>;
  }

  return (
    <div className="admin-product-manager">
      <div className="manager-header">
        <h2>Product Management</h2>
      </div>

      <div className="manager-controls">
        {!showForm && !editingId && (
          <button
            className="show-add-btn"
            onClick={() => {
              setEditingId(null);
              setShowForm(true);
              setForm({ name: '', description: '', price: '', category: '', brand: '', image: '', stock: '', visible: true });
            }}
          >
            + Add New Product
          </button>
        )}
      </div>

      {(editingId || showForm) && (
        <div className="form-container">
          <form className="product-form" onSubmit={handleAdd}>
          {error && <p className="error">{error}</p>}
          <label>Name</label>
          <input name="name" placeholder="Enter product name" value={form.name} onChange={handleChange} required />
          <label>Description</label>
          <textarea name="description" placeholder="Enter description" value={form.description} onChange={handleChange} />
          <label>Price</label>
          <input name="price" placeholder="₹0" value={form.price} onChange={handleChange} required type="number" step="0.01" />
          <label>Category</label>
          <select name="category" value={form.category} onChange={handleChange} required>
            <option value="">Select category</option>
            <option value="tv">TV</option>
            <option value="ac">AC</option>
            <option value="washing-machine">Washing Machine</option>
          </select>
          <label>Brand</label>
          <input name="brand" placeholder="Brand" value={form.brand} onChange={handleChange} />
          <label>Image URL</label>
          <input name="image" placeholder="Image link" value={form.image} onChange={handleChange} />
          <label>Or upload file</label>
          <input type="file" name="imageFile" onChange={handleFileChange} />
          <label>Stock</label>
          <input name="stock" placeholder="0" value={form.stock} onChange={handleChange} required type="number" />
          
          {editingId && (
            <div style={{backgroundColor: '#e8f4f8', padding: '1rem', borderRadius: '4px', marginTop: '1rem'}}>
              <label style={{display: 'flex', alignItems: 'center', gap: '0.75rem', margin: 0, cursor: 'pointer'}}>
                <input
                  type="checkbox"
                  checked={form.visible !== false}
                  onChange={e => setForm(prev => ({ ...prev, visible: e.target.checked }))}
                  style={{width: '18px', height: '18px', cursor: 'pointer'}}
                />
                <span style={{fontWeight: '600', color: '#2c3e50'}}>Visible to Customers</span>
              </label>
              <p style={{margin: '0.5rem 0 0 0', fontSize: '0.85rem', color: '#666'}}>
                {form.visible ? '✓ This product is visible to customers' : '⚠ Hidden from customers - Check this box to make it visible again'}
              </p>
            </div>
          )}
          <div className="form-buttons">
            <button type="submit">{editingId ? 'Update Product' : 'Add Product'}</button>
            <button type="button" onClick={() => { setEditingId(null); setShowForm(false); setForm({ name: '', description: '', price: '', category: '', brand: '', image: '', stock: '', visible: true }); }}>
              Cancel
            </button>
          </div>
          </form>
        </div>
      )}

      {loading ? (
        <p>Loading...</p>
      ) : (
        <div className="product-management-section">
          {/* Hidden Products Section - For Admin to Re-Enable */}
          {products.filter(p => !p.visible).length > 0 && (
            <div style={{marginBottom: '2rem', padding: '1.5rem', backgroundColor: '#fff3cd', border: '2px solid #ffc107', borderRadius: '8px'}}>
              <h3 style={{color: '#856404', marginTop: 0, display: 'flex', alignItems: 'center', gap: '0.5rem'}}>
                ⚠️ Hidden Products ({products.filter(p => !p.visible).length})
              </h3>
              <p style={{color: '#856404', margin: '0.5rem 0 1rem 0', fontSize: '0.9rem'}}>
                These products are hidden from customers. Click <strong>Edit</strong> and check "Visible to Customers" to make them available.
              </p>
              <div className="product-list">
                {products.filter(p => !p.visible).map(p => (
                  <div key={p._id} className="product-row" style={{backgroundColor: '#fff', borderLeft: '4px solid #ff9900', display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '1rem'}}>
                    <div>
                      <strong style={{color: '#ff6b6b', display: 'block', marginBottom: '0.5rem'}}>{p.name}</strong>
                      <small style={{color:'#888'}}>id: {p._id}</small>
                    </div>
                    <div style={{display: 'flex', gap: '0.5rem'}}>
                      <button 
                        type="button" 
                        onClick={(e) => {
                          e.preventDefault();
                          e.stopPropagation();
                          handleToggle(p);
                        }} 
                        disabled={toggleLoading === p._id}
                        style={{
                          backgroundColor: '#4CAF50', 
                          color: 'white', 
                          padding: '0.5rem 1rem', 
                          border: 'none', 
                          borderRadius: '4px', 
                          cursor: toggleLoading === p._id ? 'not-allowed' : 'pointer', 
                          fontWeight: 'bold', 
                          fontSize: '0.9rem',
                          pointerEvents: 'auto',
                          opacity: toggleLoading === p._id ? 0.6 : 1
                        }}
                      >
                        {toggleLoading === p._id ? '⏳ Saving...' : '👁️ Make Visible'}
                      </button>
                      <button 
                        type="button" 
                        onClick={(e) => {
                          e.preventDefault();
                          e.stopPropagation();
                          handleEdit(p);
                        }} 
                        style={{
                          backgroundColor: '#2196F3', 
                          color: 'white', 
                          padding: '0.5rem 1rem', 
                          border: 'none', 
                          borderRadius: '4px', 
                          cursor: 'pointer', 
                          fontWeight: 'bold', 
                          fontSize: '0.9rem',
                          pointerEvents: 'auto'
                        }}
                      >
                        ✏️ Edit
                      </button>
                      <button 
                        type="button" 
                        onClick={(e) => {
                          e.preventDefault();
                          e.stopPropagation();
                          handleDelete(p._id);
                        }} 
                        style={{
                          backgroundColor: '#f44336', 
                          color: 'white', 
                          padding: '0.5rem 1rem', 
                          border: 'none', 
                          borderRadius: '4px', 
                          cursor: 'pointer', 
                          fontSize: '0.9rem',
                          pointerEvents: 'auto'
                        }}
                      >
                        Remove
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* All Products Section */}
          <h3 style={{marginBottom: '1rem', color: '#2c3e50'}}>
            Visible Products ({products.filter(p => p.visible).length})
          </h3>
          <div className="product-list">
          {products.filter(p => p.visible).length === 0 && <p>No visible products</p>}
          {products.filter(p => p.visible).map(p => (
            <div key={p._id} className="product-row" style={{backgroundColor: '#fff', display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '1rem'}}>
              <div>
                <strong style={{display: 'block', marginBottom: '0.5rem'}}>{p.name}</strong>
                <small style={{color:'#888'}}>({p.stock} in stock)</small>
                <br />
                <small style={{color:'#888'}}>id: {p._id}</small>
              </div>
              <div style={{display: 'flex', gap: '0.5rem'}}>
                <button 
                  type="button" 
                  onClick={(e) => {
                    e.preventDefault();
                    e.stopPropagation();
                    handleEdit(p);
                  }} 
                  style={{
                    backgroundColor: '#2196F3', 
                    color: 'white', 
                    padding: '0.5rem 1rem', 
                    border: 'none', 
                    borderRadius: '4px', 
                    cursor: 'pointer', 
                    fontWeight: 'bold', 
                    fontSize: '0.9rem',
                    pointerEvents: 'auto'
                  }}
                >
                  Edit
                </button>
                <button 
                  type="button" 
                  onClick={(e) => {
                    e.preventDefault();
                    e.stopPropagation();
                    handleDelete(p._id);
                  }} 
                  style={{
                    backgroundColor: '#f44336', 
                    color: 'white', 
                    padding: '0.5rem 1rem', 
                    border: 'none', 
                    borderRadius: '4px', 
                    cursor: 'pointer', 
                    fontWeight: 'bold', 
                    fontSize: '0.9rem',
                    pointerEvents: 'auto'
                  }}
                >
                  Remove
                </button>
              </div>
            </div>
          ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminProducts;
